:host {
    height: 100%;
    width: 100%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.fleet-card {
    flex: 1;
    margin: 8px;
    background: #ffffff;
    color: #1f2937;
    border-radius: 20px;
    font-family: 'Inter', -apple-system, system-ui, sans-serif;
    box-shadow: 0 8px 24px rgba(0,0,0,.07);
    border: 1px solid #f3f4f6;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 700px;
    min-height: 280px;
}

/* ── Header ─────────────────────────────────────────────── */
.fleet-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 13px 22px;
    border-bottom: 2px solid #f3f4f6;
    flex-shrink: 0;
}

.fleet-title {
    font-weight: 800;
    font-size: 1em;
    color: #1e40af;
    letter-spacing: .07em;
    text-transform: uppercase;
}

/* ── Status badge ───────────────────────────────────────── */
.status-badge {
    padding: 4px 13px;
    border-radius: 99px;
    font-size: .70em;
    font-weight: 800;
    letter-spacing: .06em;
    transition: background .2s, color .2s;
}
.status-idle       { background:#f3f4f6; color:#6b7280; }
.status-deploying  { background:#dbeafe; color:#1d4ed8; animation: pulse .8s ease-in-out infinite; }
.status-awaiting   { background:#e0e7ff; color:#4338ca; animation: pulse 1.3s ease-in-out infinite; }
.status-complete   { background:#dcfce7; color:#166534; }
.status-partial    { background:#fef3c7; color:#92400e; animation: pulse 1.8s ease-in-out infinite; }
.status-error      { background:#fee2e2; color:#991b1b; }

@keyframes pulse {
    0%,100% { opacity:1; }
    50%      { opacity:.5; }
}

/* ── Body ───────────────────────────────────────────────── */
.fleet-body {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.col {
    display: flex;
    flex-direction: column;
    padding: 16px 20px;
    overflow-y: auto;
    min-width: 0;
}

.col-config   { flex: 1.1; border-right: 1px solid #f3f4f6; }
.col-target   { flex: 1.2; border-right: 1px solid #f3f4f6; gap: 9px; }
.col-progress { flex: 1.8; }

/* ── Column label ───────────────────────────────────────── */
.col-label {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-weight: 700;
    font-size: .65em;
    text-transform: uppercase;
    letter-spacing: .13em;
    color: #9ca3af;
    margin-bottom: 13px;
    flex-shrink: 0;
}

/* ── Inputs ─────────────────────────────────────────────── */
.input-row {
    display: flex;
    align-items: center;
    gap: 9px;
    margin-bottom: 11px;
}

.input-row label {
    font-size: .80em;
    font-weight: 600;
    color: #6b7280;
    white-space: nowrap;
    width: 52px;
    flex-shrink: 0;
}

.input-row input {
    flex: 1;
    min-width: 0;
    background: #f9fafb;
    border: 2px solid #e5e7eb;
    padding: 8px 11px;
    border-radius: 10px;
    font-weight: 500;
    font-size: .88em;
    box-sizing: border-box;
    transition: border-color .15s;
}

.input-row input:focus {
    outline: none;
    border-color: #3b82f6;
    background: #fff;
}

/* ── Radio rows ─────────────────────────────────────────── */
.radio-row {
    display: flex;
    align-items: center;
    gap: 7px;
    font-size: .88em;
    font-weight: 500;
    cursor: pointer;
    color: #374151;
    padding: 2px 0;
}

.room-badge {
    background: #eff6ff;
    color: #1d4ed8;
    font-size: .72em;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 99px;
}

/* ── Floor select ───────────────────────────────────────── */
#fa-floor-sel {
    width: 100%;
    background: #f9fafb;
    border: 2px solid #e5e7eb;
    padding: 8px 11px;
    border-radius: 10px;
    font-size: .86em;
    font-weight: 500;
    color: #374151;
    cursor: pointer;
    transition: border-color .15s, opacity .15s;
}

#fa-floor-sel:not(:disabled):focus { outline:none; border-color:#3b82f6; }
#fa-floor-sel:disabled              { opacity:.38; cursor:not-allowed; }

/* ── Deploy button ──────────────────────────────────────── */
#fa-deploy {
    margin-top: auto;
    width: 100%;
    background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%);
    color: #fff;
    border: none;
    padding: 13px;
    border-radius: 12px;
    font-weight: 700;
    font-size: .88em;
    letter-spacing: .04em;
    cursor: pointer;
    transition: opacity .2s, transform .15s;
}

#fa-deploy:not(:disabled):hover { opacity:.88; transform:translateY(-1px); }
#fa-deploy:disabled              { opacity:.60; cursor:not-allowed; transform:none; }

/* ── Total count ────────────────────────────────────────── */
.progress-count {
    font-size: 1.35em;
    font-weight: 800;
    color: #1f2937;
    letter-spacing: -.02em;
    font-variant-numeric: tabular-nums;
}

/* ── Total progress bar ─────────────────────────────────── */
.progress-track {
    height: 9px;
    background: #f3f4f6;
    border-radius: 99px;
    overflow: hidden;
    margin-bottom: 12px;
    flex-shrink: 0;
}

.progress-fill {
    height: 100%;
    width: 0%;
    background: linear-gradient(90deg,#3b82f6,#8b5cf6);
    border-radius: 99px;
    transition: width .35s ease;
}

/* ── Floor grid ─────────────────────────────────────────── */
.floor-grid {
    flex: 1;
    overflow-y: auto;
    min-height: 0;
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.grid-placeholder {
    font-size: .78em;
    color: #d1d5db;
    padding: 8px 0;
    font-style: italic;
}

.floor-row {
    display: flex;
    align-items: center;
    gap: 8px;
    min-height: 20px;
}

.floor-name {
    font-size: .72em;
    font-weight: 600;
    color: #6b7280;
    white-space: nowrap;
    width: 80px;
    flex-shrink: 0;
    overflow: hidden;
    text-overflow: ellipsis;
}

.floor-bar-track {
    flex: 1;
    height: 7px;
    background: #f3f4f6;
    border-radius: 99px;
    overflow: hidden;
}

.floor-bar-fill {
    height: 100%;
    width: 0%;
    background: linear-gradient(90deg,#60a5fa,#a78bfa);
    border-radius: 99px;
    transition: width .35s ease;
}

.floor-bar-fill.done {
    background: linear-gradient(90deg,#34d399,#10b981);
}

.floor-count {
    font-size: .70em;
    font-weight: 700;
    color: #9ca3af;
    white-space: nowrap;
    width: 44px;
    text-align: right;
    flex-shrink: 0;
    font-variant-numeric: tabular-nums;
}

.floor-count.done { color:#059669; }

/* ── Reset button ───────────────────────────────────────── */
.reset-btn {
    margin-top: 10px;
    flex-shrink: 0;
    width: 100%;
    background: transparent;
    border: 2px solid #e5e7eb;
    color: #9ca3af;
    padding: 7px;
    border-radius: 10px;
    font-weight: 600;
    font-size: .74em;
    letter-spacing: .05em;
    cursor: pointer;
    transition: all .15s;
}

.reset-btn:hover { background:#f9fafb; border-color:#d1d5db; color:#6b7280; }

/* ── Spinner ────────────────────────────────────────────── */
.spin {
    display: inline-block;
    width: 11px; height: 11px;
    border: 2px solid rgba(255,255,255,.35);
    border-top-color: #fff;
    border-radius: 50%;
    animation: spin .6s linear infinite;
    vertical-align: middle;
    margin-right: 5px;
}

@keyframes spin { to { transform:rotate(360deg); } }

.last-config-divider {
    border-top: 1px solid #f3f4f6;
    margin: 14px 0 12px;
    flex-shrink: 0;
}

.last-config-block {
    font-size: .78em;
    color: #374151;
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.lc-placeholder { color: #d1d5db; font-style: italic; }

.lc-row {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    gap: 6px;
}

.lc-key {
    font-weight: 600;
    color: #9ca3af;
    font-size: .85em;
    text-transform: uppercase;
    letter-spacing: .06em;
    white-space: nowrap;
}

.lc-val {
    font-weight: 700;
    color: #1f2937;
    text-align: right;
    word-break: break-all;
}

.lc-ts {
    font-size: .72em;
    color: #d1d5db;
    margin-top: 2px;
}

