// ── Module-level bridge (avoids closure conflict between onInit/onDataUpdated)
var _bridge = { onData: null, reset: null };

self.onInit = function () {
    var ctx = self.ctx;
    var C   = ctx.$container;

    // ── State ────────────────────────────────────────────────────────────────
    var deployedVersion = null;
    var expectedTotal   = 0;
    var deployTimer     = null;
    // entityName → { acked: Number, version: String }
    var floorState      = {};

    // ── Helpers ──────────────────────────────────────────────────────────────
    function find(sel) { return C.find(sel); }

    function setStatus(text, cls) {
        find('#fa-status').text(text).attr('class', 'status-badge ' + cls);
    }

    function totalAcked() {
        var t = 0;
        Object.keys(floorState).forEach(function (name) {
            var f = floorState[name];
            if (f.version === deployedVersion) t += (f.acked || 0);
        });
        return t;
    }

    function renderGrid() {
        var grid = find('#fa-floor-grid');
        var datasources = ctx.datasources;
        if (!datasources || datasources.length === 0) {
            grid.html('<div class="grid-placeholder">Add floor gateway devices as datasources to enable per-floor tracking.</div>');
            return;
        }
        grid.empty();
        datasources.forEach(function (ds) {
            var name  = ds.entityName || ds.name || 'Unknown';
            var f     = floorState[name] || {};
            var count = (f.version === deployedVersion) ? (f.acked || 0) : 0;
            var pct   = Math.min(100, Math.round(count / 20 * 100));
            var done  = count >= 20;
            grid.append(
                '<div class="floor-row">' +
                    '<span class="floor-name" title="' + name + '">' + name + '</span>' +
                    '<div class="floor-bar-track">' +
                        '<div class="floor-bar-fill' + (done ? ' done' : '') +
                            '" style="width:' + pct + '%"></div>' +
                    '</div>' +
                    '<span class="floor-count' + (done ? ' done' : '') + '">' +
                        count + '/20' + (done ? ' \u2713' : '') +
                    '</span>' +
                '</div>'
            );
        });
    }

    function updateProgress() {
        var got = totalAcked();
        var pct = expectedTotal > 0 ? Math.min(100, Math.round(got / expectedTotal * 100)) : 0;
        find('#fa-total-count').text(expectedTotal > 0 ? got + ' / ' + expectedTotal : '\u2014 / \u2014');
        find('#fa-total-bar').css('width', pct + '%');
        renderGrid();
        if (expectedTotal > 0 && got >= expectedTotal) {
            setStatus('COMPLETE', 'status-complete');
            if (deployTimer) { clearTimeout(deployTimer); deployTimer = null; }
        }
    }

    async function sha256hex(str) {
        var buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
        return Array.from(new Uint8Array(buf))
            .map(function (b) { return b.toString(16).padStart(2, '0'); })
            .join('');
    }

    function loadLastConfig() {
        var datasources = ctx.datasources;
        if (!datasources || datasources.length === 0) return;

        var eid = datasources[0].entity.id;
        var url = '/api/plugins/telemetry/' + eid.entityType + '/' + eid.id +
                  '/values/attributes/SHARED_SCOPE';

        ctx.http.get(url).subscribe(function (attrs) {
            var map = {};
            (attrs || []).forEach(function (a) { map[a.key] = a; });

            var cd  = map['config_data'];
            var tv  = map['target_version'];
            var tgt = map['target'];

            if (!cd || !tv) {
                find('#fa-last-config').html('<span class="lc-placeholder">No deployment recorded.</span>');
                return;
            }

            var parsed = {};
            try { parsed = JSON.parse(cd.value); } catch (e) {}

            var ts = cd.lastUpdateTs
                ? new Date(cd.lastUpdateTs).toLocaleString()
                : '';

            find('#fa-last-config').html(
                '<div class="lc-row"><span class="lc-key">Version</span>' +
                    '<span class="lc-val">' + (tv.value || '\u2014') + '</span></div>' +
                '<div class="lc-row"><span class="lc-key">Target</span>' +
                    '<span class="lc-val">' + ((tgt && tgt.value) || '\u2014') + '</span></div>' +
                '<div class="lc-row"><span class="lc-key">Alpha</span>' +
                    '<span class="lc-val">' + (parsed.alpha !== undefined ? parsed.alpha : '\u2014') + '</span></div>' +
                '<div class="lc-row"><span class="lc-key">Beta</span>' +
                    '<span class="lc-val">' + (parsed.beta !== undefined ? parsed.beta : '\u2014') + '</span></div>' +
                (ts ? '<div class="lc-ts">Updated ' + ts + '</div>' : '')
            );
        }, function () {
            find('#fa-last-config').html('<span class="lc-placeholder">Could not load last config.</span>');
        });
    }

    // ── Wire up the onDataUpdated bridge ─────────────────────────────────────
    _bridge.onData = function (dataArr) {
        dataArr.forEach(function (d) {
            var name   = d.datasource && d.datasource.entityName; if (!name) return;
            var key    = d.dataKey    && d.dataKey.name;
            var latest = d.data && d.data.length > 0 ? d.data[d.data.length - 1][1] : null;
            if (latest === null || latest === undefined) return;
            if (!floorState[name]) floorState[name] = {};
            if (key === 'ota_floor_acked')   floorState[name].acked   = parseInt(latest, 10) || 0;
            if (key === 'ota_acked_version') floorState[name].version = String(latest);
        });
        updateProgress();
    };

    _bridge.reset = function () {
        if (deployTimer) { clearTimeout(deployTimer); deployTimer = null; }
        deployedVersion = null;
        expectedTotal   = 0;
        floorState      = {};
        find('#fa-total-count').text('\u2014 / \u2014');
        find('#fa-total-bar').css('width', '0%');
        renderGrid();
        setStatus('IDLE', 'status-idle');
        find('#fa-deploy').prop('disabled', false).text('DEPLOY FLEET UPDATE');
    };

    // ── UI Bindings ──────────────────────────────────────────────────────────
    C.find('input[name="fa-tgt"]').on('change', function () {
        find('#fa-floor-sel').prop('disabled', this.value !== 'floor');
    });

    find('#fa-reset').on('click', function () { _bridge.reset(); });

    find('#fa-deploy').on('click', async function () {
        var alpha   = parseFloat(find('#fa-alpha').val());
        var beta    = parseFloat(find('#fa-beta').val());
        var version = find('#fa-version').val().trim();

        if (isNaN(alpha) || isNaN(beta))
            return ctx.showErrorToast('Enter valid alpha and beta values.');
        if (!version)
            return ctx.showErrorToast('Enter a target version string.');

        var datasources = ctx.datasources;
        if (!datasources || datasources.length === 0)
            return ctx.showErrorToast('No datasources configured. Add the 10 floor gateway devices as datasources.');

        var tgtType   = C.find('input[name="fa-tgt"]:checked').val();
        var target    = tgtType === 'floor' ? find('#fa-floor-sel').val() : 'all';
        expectedTotal = tgtType === 'floor' ? 20 : 200;

        deployedVersion = version;
        floorState      = {};
        updateProgress();

        find('#fa-deploy').prop('disabled', true).html('<span class="spin"></span>SIGNING...');
        setStatus('DEPLOYING', 'status-deploying');

        var configStr = JSON.stringify({ alpha: alpha, beta: beta, version: version });
        var sig;
        try { sig = await sha256hex(configStr); }
        catch (e) {
            ctx.showErrorToast('SHA-256 failed: ' + e.message);
            find('#fa-deploy').prop('disabled', false).text('DEPLOY FLEET UPDATE');
            setStatus('ERROR', 'status-error');
            return;
        }

        var sharedAttrs = {
            config_data:    configStr,
            signature:      sig,
            target_version: version,
            target:         target
        };

        find('#fa-deploy').html('<span class="spin"></span>DISPATCHING TO ' + datasources.length + ' FLOORS...');

        var pending  = datasources.length;
        var errCount = 0;

        function onOneDone(err) {
            if (err) errCount++;
            if (--pending > 0) return;

            find('#fa-deploy').prop('disabled', false).text('DEPLOY FLEET UPDATE');

            if (errCount === datasources.length) {
                setStatus('ERROR', 'status-error');
                ctx.showErrorToast('All dispatches failed. Check datasource permissions.');
                return;
            }
            if (errCount > 0)
                ctx.showWarnToast(errCount + ' floor(s) failed to receive attributes.');

            setStatus('AWAITING ACKS', 'status-awaiting');
            loadLastConfig();

            if (deployTimer) clearTimeout(deployTimer);
            deployTimer = setTimeout(function () {
                deployTimer = null;
                var n = totalAcked();
                if (n < expectedTotal) {
                    ctx.showWarnToast('Timeout \u2014 ' + n + ' / ' + expectedTotal + ' rooms responded.');
                    setStatus('PARTIAL ' + n + '/' + expectedTotal, 'status-partial');
                }
            }, 45000);
        }

        // POST OTA config as SHARED ATTRIBUTES to each floor gateway device.
        // ThingsBoard pushes { shared: {config_data, signature, ...} } via
        // v1/devices/me/attributes to the Node-RED worker's persistent TB connection.
        datasources.forEach(function (ds) {
            var eid = ds.entity.id;
            var url = '/api/plugins/telemetry/' + eid.entityType + '/' + eid.id + '/attributes/SHARED_SCOPE';
            ctx.http.post(url, sharedAttrs).subscribe(
                function ()    { onOneDone(false); },
                function (err) {
                    ctx.showErrorToast('Floor "' + (ds.entityName || eid.id) + '" failed: ' +
                        (err.status ? err.status + ' ' + (err.error || '') : err.message || err));
                    onOneDone(true);
                }
            );
        });
    });

    // ── Initial render ───────────────────────────────────────────────────────
    renderGrid();
    loadLastConfig();
};

self.onDataUpdated = function () {
    if (_bridge.onData && self.ctx.defaultSubscription) {
        _bridge.onData(self.ctx.defaultSubscription.data || []);
    }
};

self.onDestroy = function () {
    _bridge.onData  = null;
    _bridge.reset   = null;
};

self.typeParameters = function () {
    return { maxDatasources: 10, maxDataKeys: 2 };
};

